package authz

import "maps"

// Check describes a single authorization requirement. ResourceID identifies the
// resource. ResourceKind overrides the kind derived from the scope — leave empty
// to derive automatically. Dimensions carry optional narrowing attributes (tool,
// disposition, collection) for multi-dimensional checks.
type Check struct {
	Scope        Scope
	ResourceKind string
	ResourceID   string
	Dimensions   map[string]string
	// expanded is true for checks generated by scope expansion (parent scopes).
	// Deny grants only apply to the original scope, not expanded parents.
	expanded bool
}

// selector converts the check into a Selector for matching against grant selectors.
func (c Check) selector() Selector {
	kind := c.ResourceKind
	if kind == "" {
		kind = ResourceKindForScope(c.Scope)
	}
	s := Selector{
		"resource_kind": kind,
		"resource_id":   c.ResourceID,
	}
	maps.Copy(s, c.Dimensions)
	return s
}

// expand returns all scope variants that would satisfy this check: the check's
// own scope, any higher-privilege scopes that imply it, and ScopeRoot. Selector
// matching handles wildcard grants natively ({"resource_id":"*"} matches any
// check), so we only need one entry per scope level.
func (c Check) expand() []Check {
	checks := []Check{
		// ScopeRoot is expanded — only allows should match it, not denies.
		{Scope: ScopeRoot, ResourceKind: c.ResourceKind, ResourceID: c.ResourceID, Dimensions: c.Dimensions, expanded: true},
		// The original scope is not expanded — both allows and denies match it.
		{Scope: c.Scope, ResourceKind: c.ResourceKind, ResourceID: c.ResourceID, Dimensions: c.Dimensions},
	}
	// Higher-privilege parent scopes that also satisfy this check (for allow matching only).
	for _, s := range scopeExpansions[c.Scope] {
		checks = append(checks, Check{Scope: s, ResourceKind: c.ResourceKind, ResourceID: c.ResourceID, Dimensions: c.Dimensions, expanded: true})
	}
	return checks
}
